    N *x = y->l;
    N *T = x->r;
    x->r = y;   // BUG: devrait aussi mettre y->l = T
    // y->l = T; // cette ligne manque
    upd(y); upd(x);
    return x;
}

N *rot_left(N *x) {
    N *y = x->r;
    N *T = y->l;
    y->l = x;
    x->r = T;
    upd(x); upd(y);
    return y;
}

N *insert(N *n, int v) {
    if (!n) return new_node(v);
    if (v < n->val) n->l = insert(n->l, v);
    else if (v > n->val) n->r = insert(n->r, v);
